issue_match.bdrl_program:
# Match JVM crashes and categorize by exception type.
# The bitdrift-shop demo triggers: NullPointerException, StackOverflowError, OutOfMemoryError.
if .type != 3 || length(.errors) == 0 {
  abort
}
name = string(.errors[0].name) ?? ""
if contains(name, "NullPointerException") {
  add_field("crash_category", "null_pointer")
} else if contains(name, "StackOverflowError") {
  add_field("crash_category", "stack_overflow")
} else if contains(name, "OutOfMemoryError") {
  add_field("crash_category", "oom")
} else {
  add_field("crash_category", "other_jvm")
}
